import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const MovingGallery = () => {
  const images = [
    "/assets/amb.jpg",
    "/assets/apr.jpg",
    "/assets/ballent.jpg",
    "/assets/bl.jpg",
    "/assets/bn.jpg",
    "/assets/dj.jpg",
    "/assets/dri.jpg",
    "/assets/f1.jpg",
    "/assets/grp.jpg",
    "/assets/nod.jpg",
    "/assets/pic.jpg",
    "/assets/piz.jpg"
  ];

  const videos = [
    "/assets/videos/cooking.mp4",
    "/assets/videos/vid2.mp4",
    "/assets/videos/vid3.mp4",
    "/assets/videos/vid5.mp4",
    "/assets/videos/vid6.mp4"
  ];

  return (
    <section className="py-24 bg-black overflow-hidden">
      {/* Title */}
      <motion.div className="text-center mb-20" initial={{ opacity: 0 }} whileInView={{ opacity: 1 }}>
        <span className="font-accent inline-block text-gold text-sm tracking-[0.25em] uppercase px-8 py-3 bg-black rounded-full border border-gold">
          Gallery
        </span>
        <h2 className="font-heading text-4xl md:text-5xl lg:text-6xl text-white mt-8 leading-tight">
          Corridor Moments
        </h2>
      </motion.div>

      {/* Videos Portrait */}
      <motion.div className="mb-16 opacity-100 z-10" initial={{ opacity: 0 }} whileInView={{ opacity: 1 }}>
        <Marquee speed={25} gradient={false} pauseOnHover className="p-8">
          {videos.concat(videos).map((src, i) => (
            <video
              key={i}
              src={src}
              className="mx-2 w-[220px] h-[400px] object-cover rounded-3xl shadow-2xl border-2 border-white/50 opacity-100 block"
              muted
              autoPlay
              loop
              playsInline
              preload="auto"
            />
          ))}
        </Marquee>
      </motion.div>

      {/* Images LTR */}
      <motion.div className="mb-16 opacity-100 z-10" initial={{ opacity: 0 }} whileInView={{ opacity: 1 }}>
        <div className="p-12">
          <Marquee speed={45} gradient={false} pauseOnHover>
            {images.map((src, i) => (
              <motion.img
                key={i}
                src={src}
                className="mx-2 w-[320px] h-[240px] object-cover rounded-2xl shadow-2xl border-4 border-white/30 opacity-100 block grayscale hover:grayscale-0 hover:scale-105 hover:shadow-white/50 transition-all duration-500"
                loading="eager"
                whileHover={{ scale: 1.03 }}
              />
            ))}
          </Marquee>
        </div>
      </motion.div>

      {/* Images RTL */}
      <motion.div className="opacity-100 z-10" initial={{ opacity: 0 }} whileInView={{ opacity: 1 }}>
        <div className="p-12">
          <Marquee speed={45} direction="right" gradient={false} pauseOnHover>
            {images.slice(0, 11).map((src, i) => (
              <motion.img
                key={"r" + i}
                src={src}
                className="mx-2 w-[320px] h-[240px] object-cover rounded-2xl shadow-2xl border-4 border-white/30 opacity-100 block grayscale hover:grayscale-0 hover:scale-105 hover:shadow-white/50 transition-all duration-500"
                loading="eager"
                whileHover={{ scale: 1.03 }}
              />
            ))}
          </Marquee>
        </div>
      </motion.div>
    </section>
  );
};

export default MovingGallery;
